import React, { useEffect, useState } from 'react'
import { userService } from '../../services/api'
import { useAuth } from '../../context/AuthContext'
import '../../styles/dashboard.css'
import '../../styles/admin/admin-users.css'

const ROLE_OPTIONS = [
  { value: 'MANAGER', label: 'Quản lý' },
  { value: 'TECHNICIAN', label: 'Kỹ thuật' },
  { value: 'WORKER', label: 'Công nhân' },
  { value: 'ACCOUNTANT', label: 'Kế toán' },
  { value: 'STOREKEEPER', label: 'Quản lý kho' },
]

const OwnerManageStaff = () => {
  const { user } = useAuth()
  const [staff, setStaff] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [selectedUser, setSelectedUser] = useState(null)
  const [roleValue, setRoleValue] = useState('')

  useEffect(() => {
    fetchStaff()
  }, [])

  const fetchStaff = async () => {
    try {
      setLoading(true)
      const res = await userService.getWorkers()
      const list = res?.data?.data || []
      // If OWNER, filter to own farm
      const currentRole = String(user?.role || '').toUpperCase()
      const farmId = user?.farm_id || null
      const filtered = currentRole === 'OWNER' ? list.filter(u => String(u.farm_id || '') === String(farmId || '')) : list
      setStaff(filtered)
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Lỗi tải danh sách nhân viên')
    } finally {
      setLoading(false)
    }
  }

  const getAvatarUrl = (user) => user?.avatar_url || user?.avatarUrl || ''
  const getAvatar = (fullName) => {
    const name = String(fullName || '').trim()
    if (!name) return 'U'
    const parts = name.split(/\s+/).filter(Boolean)
    if (parts.length === 1) return parts[0].charAt(0).toUpperCase()
    return `${parts[0].charAt(0)}${parts[parts.length - 1].charAt(0)}`.toUpperCase()
  }

  const openEditRole = (u) => {
    setSelectedUser(u)
    setRoleValue(String(u.role || 'WORKER').toUpperCase())
    setShowModal(true)
    setError('')
    setSuccess('')
  }

  const closeModal = () => {
    setShowModal(false)
    setSelectedUser(null)
  }

  const handleSaveRole = async (e) => {
    e.preventDefault()
    if (!selectedUser) return
    try {
      await userService.updateUserRoleByName(selectedUser.user_id, roleValue)
      setSuccess('Đã cập nhật vai trò')
      closeModal()
      await fetchStaff()
    } catch (err) {
      setError(err?.response?.data?.message || 'Lỗi cập nhật vai trò')
    }
  }

  const handleResetPassword = async (userId) => {
    if (!window.confirm('Bạn có chắc chắn muốn reset mật khẩu tài khoản này?')) return
    try {
      await userService.resetPassword(userId)
      setSuccess('Đã reset mật khẩu (mặc định được gửi)')
      await fetchStaff()
    } catch (err) {
      setError(err?.response?.data?.message || 'Lỗi reset mật khẩu')
    }
  }

  const handleRemoveFromFarm = async (userId) => {
    if (!window.confirm('Bạn chắc chắn muốn gỡ người dùng này khỏi trại?')) return
    try {
      await userService.removeFromFarm(userId)
      setSuccess('Đã gỡ người dùng khỏi trại')
      await fetchStaff()
    } catch (err) {
      setError(err?.response?.data?.message || 'Lỗi khi gỡ người dùng khỏi trại')
    }
  }

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center" style={{ height: '60vh' }}>
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard admin-page">
      <h2>Quản lý nhân viên</h2>
      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="table-wrapper">
        <table className="admin-users__table">
          <thead>
            <tr>
              <th>Ảnh</th>
              <th>Họ tên</th>
              <th>Tên đăng nhập</th>
              <th>Email</th>
              <th>Số điện thoại</th>
              <th>Vai trò</th>
              <th>Hành động</th>
            </tr>
          </thead>
          <tbody>
            {staff.length === 0 ? (
              <tr>
                <td colSpan="7" className="admin-users__empty-row">Không có nhân viên</td>
              </tr>
            ) : (
              staff.map((u) => (
                <tr key={u.user_id}>
                  <td>
                    <div className="admin-users__avatar">
                      {getAvatarUrl(u) ? (
                        <img src={getAvatarUrl(u)} alt={u.full_name || u.username} className="admin-users__avatar-image" />
                      ) : (
                        getAvatar(u.full_name)
                      )}
                    </div>
                  </td>
                  <td>{u.full_name}</td>
                  <td>{u.username}</td>
                  <td>{u.email}</td>
                  <td>{u.phone || '-'}</td>
                  <td><span className={`admin-users__role`}>{u.role}</span></td>
                  <td>
                    <div className="admin-users__table-actions">
                      <button className="btn btn-sm btn-secondary" onClick={() => openEditRole(u)} title="Chỉnh vai trò">✎</button>
                      <button className="btn btn-sm btn-warning" onClick={() => handleResetPassword(u.user_id)} title="Reset mật khẩu">↺</button>
                      <button className="btn btn-sm btn-danger" onClick={() => handleRemoveFromFarm(u.user_id)} title="Gỡ khỏi trại">🗑️</button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {showModal && (
        <div className="modal" onClick={closeModal}>
          <div className="modal-content admin-users__modal" onClick={(e) => e.stopPropagation()}>
            <button type="button" className="admin-users__modal-close" onClick={(e) => { e.stopPropagation(); closeModal(); }} aria-label="Close">×</button>
            <h3>Chỉnh vai trò</h3>
            <form onSubmit={handleSaveRole}>
              <div className="form-group">
                <label>Vai trò</label>
                <select value={roleValue} onChange={(e) => setRoleValue(e.target.value)} required>
                  {ROLE_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>

              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                <button type="button" className="btn btn-secondary" onClick={closeModal}>Hủy</button>
                <button type="submit" className="btn btn-primary">Lưu</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default OwnerManageStaff
